local _M = {}

function _M.match(user_agent)
  if type(user_agent) ~= 'string' or user_agent == '' then
    return nil
  end

  local s = string_lower(user_agent)
  local state = 1
  local best = nil

  for i = 1, #s do
    local b = string_byte(s, i)
    local trans = TRANSITIONS[state]
    while state ~= 1 and (not trans or trans[b] == nil) do
      state = FAIL[state] or 1
      trans = TRANSITIONS[state]
    end

    if trans and trans[b] ~= nil then
      state = trans[b]
    else
      state = 1
    end

    local outs = OUTPUTS[state]
    if outs then
      for j = 1, #outs do
        local candidate = outs[j]
        if best == nil or candidate.length > best.length then
          best = candidate
        end
      end
    end
  end

  return best
end

return _M
